(9, 'Uninox Steel & Plast', 'info@uninoxhouseware.com', '07942537867', '', '07AASCA3318G1ZN', 'https://www.uninoxhouseware.in/', '', 'Bhiwadi, Rajasthan, 301019', 'Uninox is an ISO 9001:2008 certified company takes great pride in manufacturing high quality kitchenware stainless steel products. We are one of the most experienced kitchenware stainless steel manufacturing companies in India.', '', '', '', '', '2026-01-06 11:45:35'),
